import React, { useEffect, useState } from 'react';

function Historial({ entrevistadorId, onVolver }) {
  const [entrevistas, setEntrevistas] = useState([]);
  const [error, setError] = useState('');

  useEffect(() => {
    fetch("http://localhost/sistema-entrevistas/backend/api/historial_entrevistas.php", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ entrevistador_id: entrevistadorId })
    })
      .then(res => res.json())
      .then(data => {
        if (data.status === "ok") {
          setEntrevistas(data.entrevistas);
        } else {
          setError(data.mensaje || "No se pudo obtener el historial.");
        }
      })
      .catch(() => setError("Error de conexión con el servidor."));
  }, [entrevistadorId]);

  return (
    <div>
      <h2>Historial de entrevistas</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}

      {entrevistas.map((e, i) => (
        <div key={i} style={{ marginBottom: '15px', padding: '10px', background: '#f9f9f9' }}>
          <strong>Postulante:</strong> {e.postulante} <br />
          <strong>Fecha:</strong> {e.fecha} <br />
          <strong>Evaluación:</strong> {e.evaluacion_automatica.slice(0, 100)}... <br />
        </div>
      ))}

      <button onClick={onVolver} style={{ marginTop: '10px' }}>
        Volver
      </button>
    </div>
  );
}

export default Historial;
